// ════════════════════════════════════════════════════════
// TOOL: SALVAR AGENDAMENTO
// Cria agendamento + vincula serviço/funcionário + cria bloqueio
// Replica a lógica do AgendamentoService.criarAgendamento()
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
let clienteId = input.cliente_id || input.clienteId;
let servicoId = input.servico_id || input.servicoId;
let funcionarioId = input.funcionario_id || input.funcionarioId;
let data = input.data || null;
let hora = input.hora || null;
let observacao = input.observacao || 'Agendamento via WhatsApp';

// Tentar extrair dados do query
if (query) {
  if (!clienteId) {
    const m = query.match(/cliente[_\s]?(?:id)?[:\s]*(\d+)/i);
    if (m) clienteId = m[1];
  }
  if (!servicoId) {
    const m = query.match(/servico[_\s]?(?:id)?[:\s]*(\d+)/i);
    if (m) servicoId = m[1];
  }
  if (!funcionarioId) {
    const m = query.match(/funcionario[_\s]?(?:id)?[:\s]*(\d+)/i);
    if (m) funcionarioId = m[1];
  }
  if (!data) {
    const m = query.match(/(\d{4}-\d{2}-\d{2})/);
    if (m) data = m[1];
    else {
      const m2 = query.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (m2) data = `${m2[3]}-${m2[2].padStart(2, '0')}-${m2[1].padStart(2, '0')}`;
    }
  }
  if (!hora) {
    const m = query.match(/(\d{1,2}):(\d{2})/);
    if (m) hora = `${m[1].padStart(2, '0')}:${m[2]}`;
  }
}

// Validação
const erros = [];
if (!clienteId) erros.push('cliente_id');
if (!servicoId) erros.push('servico_id');
if (!funcionarioId) erros.push('funcionario_id');
if (!data) erros.push('data (YYYY-MM-DD)');
if (!hora) erros.push('hora (HH:MM)');
if (!organizacaoId) erros.push('organizacao_id');

if (erros.length > 0) {
  return [{
    json: {
      error: true,
      message: `Dados incompletos para criar agendamento. Faltam: ${erros.join(', ')}.`
    }
  }];
}

// Validar data não é no passado
const dtAgendamento = new Date(`${data}T${hora}:00`);
const agora = new Date();
if (dtAgendamento < agora) {
  return [{
    json: {
      error: true,
      message: 'Não é possível agendar para o passado. Escolha uma data/horário futuros.'
    }
  }];
}

return [{
  json: {
    cliente_id: clienteId,
    servico_id: servicoId,
    funcionario_id: funcionarioId,
    data: data,
    hora: hora,
    organizacao_id: organizacaoId,
    observacao: observacao,
    dt_agendamento: `${data}T${hora}:00`
  }
}];

// Verificar se o dia está bloqueado
const resultado = $input.item.json;
const params = $('Extrair e Validar Parâmetros').item.json;

if (resultado && resultado.id) {
  return [{
    json: {
      error: true,
      message: `Não é possível agendar para ${params.data}. O dia está bloqueado (feriado ou bloqueio da organização).`
    }
  }];
}

return [{ json: { ...params, bloqueio_ok: true } }];

// Preparar dados para inserção
const params = $('Avaliar Bloqueio').item.json;
const duracao = $input.item.json.duracao || 30;

return [{
  json: {
    ...params,
    duracao: duracao,
    dt_fim_bloqueio_str: '' // será calculado na query SQL
  }
}];

// Salvar agendamento_id para os próximos passos
const agendamentoId = $input.item.json.agendamento_id;
const params = $('Preparar Inserção').item.json;

return [{
  json: {
    ...params,
    agendamento_id: agendamentoId
  }
}];

// ════════════════════════════════════════════════════════
// FORMATAR RESPOSTA DE SUCESSO
// ════════════════════════════════════════════════════════

const dados = $input.item.json;
const params = $('Salvar ID').item.json;

// Formatar data
const dataFormatada = params.data.split('-').reverse().join('/');

const resposta = {
  sucesso: true,
  agendamento_id: dados.agendamento_id || params.agendamento_id,
  status: dados.status || 'PENDENTE',
  cliente: dados.cliente_nome,
  servico: dados.servico_nome,
  preco: `R$ ${parseFloat(dados.servico_preco || 0).toFixed(2).replace('.', ',')}`,
  duracao: `${dados.servico_duracao || params.duracao} min`,
  profissional: dados.funcionario_nome,
  data: dataFormatada,
  horario: params.hora,
  mensagem: 'Agendamento criado com sucesso!'
};

return [{
  json: {
    response: JSON.stringify(resposta)
  }
}];
